    contact: [{ _attributes: { callsign: callsign } }],
    remarks: remarks,
    labels_on: [{ _attributes: { value: (cls.labelsOn != null ? cls.labelsOn : cfg.style.labelsOn) ? 'true' : 'false' } }]
  };
