  if (!noColor) detail.strokeWeight = [{ _attributes: { value: String(cfg.style.strokeWeight || 3) + '.0' } }];
  if (fFillArgb != null) detail.fillColor = [{ _attributes: { value: String(fFillArgb) } }];

