      { payload: feat.cot, topic: topicCfg,
        _missionName: cfg.missionName,
        host: host,
        port: Number(cfg.cotStreamPort) || Number(cfg.streamPort) || Number(tak.streamingPort) || Number(tak.streamPort) || 8089 },
      null
